import{_ as t,o as a,c as o,a6 as i}from"./chunks/framework.CG5ubMb2.js";const f=JSON.parse('{"title":"Fake timers","description":"Replace setTimeout, setInterval, and Date with controllable fake implementations for time-based testing.","frontmatter":{"title":"Fake timers","description":"Replace setTimeout, setInterval, and Date with controllable fake implementations for time-based testing."},"headers":[],"relativePath":"concepts/fake-timers/index.md","filePath":"concepts/fake-timers/index.md"}'),r={name:"concepts/fake-timers/index.md"};function s(n,e,d,c,m,l){return a(),o("div",null,[...e[0]||(e[0]=[i('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /concepts/fake-timers.md for this page in Markdown format</div><h1 id="fake-timers" tabindex="-1">Fake timers <a class="header-anchor" href="#fake-timers" aria-label="Permalink to “Fake timers”">​</a></h1><p>Fake timers are synchronous implementations of <code>setTimeout</code> and friends that Sinon.JS can overwrite the global functions with to allow you to more easily test code using them.</p><p>Fake timers provide a <code>clock</code> object to pass time, which can also be used to control <code>Date</code> objects created through either <code>new Date();</code> or <code>Date.now();</code> (if supported by the browser).</p><p>For standalone usage of fake timers it is recommended to use <a href="https://github.com/sinonjs/fake-timers" target="_blank" rel="noreferrer">fake-timers</a> package instead. It provides the same set of features (Sinon uses it under the hood) and was previously extracted from Sinon.JS.</p>',5)])])}const h=t(r,[["render",s]]);export{f as __pageData,h as default};
